  /**
   * ZZ_ATTRIBUTE[aState] contains the attributes of state {@code aState}
   */
  private static final int [] ZZ_ATTRIBUTE = zzUnpackAttribute();

  private static final String ZZ_ATTRIBUTE_PACKED_0 =
    "\2\0\1\11\2\1\1\11\2\1\1\11\1\1\6\11"+
    "\3\1\1\11\3\1\1\11\21\1\3\11\16\1\1\11"+
    "\1\1\1\11\1\1\2\11\1\1\1\0\1\11\1\0"+
    "\2\11\2\0\3\11\46\1\1\11\1\1\1\11\2\0"+
    "\53\1\1\11\50\1\1\0\20\1\1\0\11\1\1\0"+
    "\6\1\1\0\14\1\1\0\11\1\1\0\1\1\1\11"+
    "\13\1\1\0\3\1\1\0\11\1\1\0\1\1\1\0"+
    "\7\1\1\0\1\1\1\11\7\1\1\0\6\1\1\0"+
    "\1\11\6\1\1\0\5\1\1\0\3\1\1\0\3\1"+
    "\1\0\2\1\1\11\5\1";

  private static int [] zzUnpackAttribute() {
    int [] result = new int[345];
    int offset = 0;
    offset = zzUnpackAttribute(ZZ_ATTRIBUTE_PACKED_0, offset, result);
    return result;
  }

  private static int zzUnpackAttribute(String packed, int offset, int [] result) {
    int i = 0;       /* index in packed string  */
    int j = offset;  /* index in unpacked array */
    int l = packed.length();
    while (i < l) {
      int count = packed.charAt(i++);
      int value = packed.charAt(i++);
      do result[j++] = value; while (--count > 0);
    }
    return j;
  }

